mapper.select:
SELECT id, org_id AS orgId, operation_id AS operationId, start_time AS startTime, end_time AS endTime, operation_level AS operationLevel, affected_households AS affectedHouseholds, reason, remark, status, create_time AS createTime, create_id AS createId, update_time AS updateTime, update_id AS updateId FROM gs_cutoff_plan
deleted = 0
AND start_time >= #{request.startTime}
AND end_time <= #{request.endTime}
AND operation_level = #{request.operationType}
ORDER BY update_time DESC
